import ReactPlayer from 'react-player/lazy';
import CollapsedText from './CustomCollapsedText';

import "../styles/CustomVideoCard.css";
import CustomCard from './CustomCard';

{/*CustomVideoCard recibe url, title, description y component.*/}
{/*CustomVideoCard permite reproducir un video.*/}

function CollapsedVideoCard({ url, title, description, component }) {
  return (
    <>
       <CustomCard>
       <div className="video-container mb-3">
          <ReactPlayer
            url={url}
            controls
            width='100%'
            height='100%'
            loop
            muted
            style={{ position: 'absolute', top: 0, left: 0 }}
          />
        </div>
        <div className="w-100">
          <CollapsedText title={title} description={description} maxLines={3} component={component}/>
        </div>
       </CustomCard>
      </>
  );
}

export default CollapsedVideoCard;
